/**
 * StylePresetsBar — Barra de presets de estilo rápido
 *
 * Exibe 5 presets (Título, Subtítulo, Corpo, Callout, Código) com preview visual.
 * Click aplica o preset completo. Funções puras de formatação exportadas para testes.
 */

'use client';

import React, { useCallback } from 'react';
import { Label } from '@/components/ui/label';
import { cn } from '@/lib/utils';
import {
  type TextStylePreset,
  STYLE_PRESETS,
  textStyleToCSS,
} from '@/lib/typography/font-manager';

// ─── Pure helpers (exportados para testes) ─────────────────────────

/**
 * Gera a preview label curta para um preset.
 */
export function presetPreviewLabel(preset: TextStylePreset): string {
  return `${preset.config.weight} ${preset.config.size}px`;
}

/**
 * Retorna o style CSS para preview de um preset na barra.
 */
export function presetPreviewStyle(preset: TextStylePreset): Record<string, string | number> {
  return textStyleToCSS(preset.config, preset.effects);
}

// ─── Types ─────────────────────────────────────────────────────────

export interface StylePresetsBarProps {
  /** Preset atualmente selecionado */
  activePreset?: string;
  /** Callback ao selecionar um preset */
  onPresetSelect: (preset: TextStylePreset) => void;
  /** Classes CSS adicionais */
  className?: string;
}

// ─── Component ─────────────────────────────────────────────────────

export function StylePresetsBar({
  activePreset,
  onPresetSelect,
  className,
}: StylePresetsBarProps) {
  const handleClick = useCallback(
    (preset: TextStylePreset) => {
      onPresetSelect(preset);
    },
    [onPresetSelect],
  );

  return (
    <div className={cn('flex flex-col gap-2 rounded-lg bg-zinc-900 p-3 border border-zinc-700', className)}>
      <Label className="text-xs font-medium text-zinc-400">Presets de Estilo</Label>
      <div className="flex flex-wrap gap-2">
        {STYLE_PRESETS.map((preset) => {
          const isActive = activePreset === preset.name;
          const style = presetPreviewStyle(preset);
          return (
            <button
              key={preset.name}
              type="button"
              onClick={() => handleClick(preset)}
              className={cn(
                'flex flex-col items-center gap-1 rounded-lg border px-3 py-2 transition-all',
                isActive
                  ? 'border-emerald-500 bg-zinc-800 ring-1 ring-emerald-500/30'
                  : 'border-zinc-700 bg-zinc-800/50 hover:border-zinc-600 hover:bg-zinc-800',
              )}
            >
              <span
                style={{
                  ...style,
                  fontSize: `${Math.min(Number(preset.config.size), 20)}px`,
                  lineHeight: 1.2,
                }}
                className={cn(isActive ? 'text-white' : 'text-zinc-300')}
              >
                {preset.label}
              </span>
              <span className="text-[10px] text-zinc-500">
                {presetPreviewLabel(preset)}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

export default StylePresetsBar;
